mapper.select:
select *
from ${tableName}


        address_id = ${addressId}



    order by ${orderColumn} desc


    limit ${startCount}, ${limitSize}

select *
from device.x_device_android_address_all
where did_key = #{key} and address_id = #{addressId}

select did
from ${tableName}


        crowd_id = ${crowdId}



    order by ${orderColumn}


    limit ${startCount}, ${limitSize}

select address_id
from ${tableName}
group by address_id

select did ,count(distinct request_id) as frequency from statics_imp_new_all
where last_update_time >=#{startTime} and last_update_time <#{endTime}
  and ad_campaign_id = #{campaignId}
group by did

select *
from ${tableName}

    did global in ( select did from  adanxing.device_crowd_ta_ott
    where log_time >='2024-01-17 22:30:00' and tag_type=1 and tag_value global in (8,9,10,11)
    and did !='')

       and address_id = ${addressId}




    order by ${orderColumn}


    limit ${startCount}, ${limitSize}

select *
from ${tableName}

    did global in ( select did from  adanxing.device_crowd_ta_ott
    where log_time >='2024-01-17 22:30:00' and tag_type=1 and tag_value global not in (8,9,10,11) and did !='')

        and address_id = ${addressId}




    order by ${orderColumn}


    limit ${startCount}, ${limitSize}

select SUBSTRING(logTimeH,12,2) as h ,did,did_type ,age_tag as age,sex_tag as sex from
    (select DISTINCT formatDateTime(log_time,'%Y-%m-%d %H') as logTimeH ,did,did_type ,age_tag ,sex_tag from ${tableName}
     order by logTimeH desc,did
    )
limit 1 by h,did,did_type

select did,did_type ,age_tag as age,sex_tag as sex ,log_time as logTime from
    (select DISTINCT log_time,did,did_type ,age_tag ,sex_tag from ${tableName}
     order by log_time desc,did
    )
limit 1 by did,did_type
